# -- Helpers --
import textwrap as _tw

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()


def _secret_for_snippet(index):
    secret = _open_secret(SNIPPET_SECRETS[index - 1], "implicit-conversion-minefield:snippet:" + str(index))
    if secret is None:
        print("  [error] Could not open snippet quiz-data -- contact your instructor.")
        sys.exit(1)
    return secret

def _find_compiler():
    for c in ("g++", "clang++"):
        if subprocess.run(["which", c], capture_output=True).returncode == 0:
            return c
    return None


def _compile_run(code, compiler, tmpdir, idx):
    src = os.path.join(tmpdir, f"s{idx:02}.cpp")
    exe = os.path.join(tmpdir, f"s{idx:02}")
    with open(src, "w") as f:
        f.write(code)
    r = subprocess.run([compiler, "-std=c++17", "-o", exe, src],
                       capture_output=True, text=True)
    if r.returncode != 0:
        return None, r.stderr
    r = subprocess.run([exe], capture_output=True, text=True, timeout=5)
    return r.stdout.strip(), None


def _ask(s, actual, index, total):
    secret = _secret_for_snippet(index)
    print(f"\n{' ':=<70}")
    print(f"  Snippet {index:02}/{total:02}: {s['title']}")
    print(f"{' ':=<70}")
    if s.get("platform_note"):
        print(f"  Platform: {s['platform_note']}")
    print()
    for line in s["code"].splitlines():
        print(f"    {line}")
    print()
    print(f"  {s['prompt']}")
    attempts = 0
    while True:
        raw = input("  Your prediction: ").strip()
        if not raw:
            continue
        if raw == actual:
            if attempts > 0:
                for ln in _wrap(secret.get("explanation", "")):
                    print(ln)
            else:
                print(f"  Correct.  {secret.get('explanation', '')}")
            return raw
        attempts += 1
        _show_wrong(raw, secret.get("wrong") or {})
        print(f"  Actual output: {actual!r}   Type it exactly to continue.")


def main():
    _banner("Activity 2: Implicit Conversion Minefield")
    print()
    input("  Press Enter to begin...")

    compiler = _find_compiler()
    if not compiler:
        print("error: no C++ compiler found (need g++ or clang++)", file=sys.stderr)
        sys.exit(1)

    print(f"\n  Compiling snippets with {compiler}...", end=" ", flush=True)
    actuals = []
    with tempfile.TemporaryDirectory(prefix="implicit-conversion-minefield-") as tmpdir:
        for s in SNIPPETS:
            out, err = _compile_run(s["code"], compiler, tmpdir, s["id"])
            if out is None:
                print(f"FAILED\nerror: snippet {s['id']} compile error:\n{err}",
                      file=sys.stderr)
                sys.exit(1)
            actuals.append(out)
    print("done")

    answers = []
    for i, (s, actual) in enumerate(zip(SNIPPETS, actuals), 1):
        answers.append(_ask(s, actual, i, len(SNIPPETS)))

    print()
    print("  All correct.")
    passphrase = _decrypt(_BLOB, answers)
    if passphrase is None:
        print("  [error] Decryption failed -- contact your instructor.")
        sys.exit(1)
    _show_passphrase(passphrase)


if __name__ == "__main__":
    main()
